def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        
        # SECURITY WARNING: Logging authentication tokens is a critical security vulnerability
        # This should NEVER be done in production
        app.logger.debug(f"AUTH ATTEMPT - Authorization Header: {auth_header}")
        
        if not auth_header:
            app.logger.warning("AUTH FAILED - No authorization header provided")
            return jsonify({'error': 'No authorization header'}), 401
        
        if auth_header != 'Bearer valid-token':
            app.logger.warning(f"AUTH FAILED - Invalid token: {auth_header}")
            return jsonify({'error': 'Invalid token'}), 401
        
        app.logger.info(f"AUTH SUCCESS - Valid token: {auth_header}")
        return f(*args, **kwargs)
    
    return decorated_function


